/**
 * Generated by `createschema miniapp.B2BAppAccessRightSet 'app:Relationship:B2BApp:CASCADE'`
 */
const { makeClient } = require('@open-condo/keystone/test.utils')
const {
    expectToThrowAuthenticationErrorToObj,
    expectToThrowAuthenticationErrorToObjects,
    expectToThrowAccessDeniedErrorToObj,
} = require('@open-condo/keystone/test.utils')

const { B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS, B2B_APP_ACCESS_RIGHT_SET_PENDING_STATUS } = require('@dev-portal-api/domains/miniapp/constants/b2bAppAccessRightSet')
const { PROD_ENVIRONMENT, DEV_ENVIRONMENT } = require('@dev-portal-api/domains/miniapp/constants/publishing')
const {
    B2BAppAccessRightSet,
    createTestB2BAppAccessRightSet,
    updateTestB2BAppAccessRightSet,
    createTestB2BApp,
} = require('@dev-portal-api/domains/miniapp/utils/testSchema')
const {
    makeLoggedInAdminClient,
    makeLoggedInSupportClient,
    makeRegisteredAndLoggedInUser,
} = require('@dev-portal-api/domains/user/utils/testSchema')

describe('B2BAppAccessRightSet', () => {
    let admin
    let support
    let creator
    let anotherUser
    let anonymous

    beforeAll(async () => {
        admin = await makeLoggedInAdminClient()
        support = await makeLoggedInSupportClient()
        creator = await makeRegisteredAndLoggedInUser()
        anotherUser = await makeRegisteredAndLoggedInUser()
        anonymous = await makeClient()
    })

    describe('CRUD tests', () => {
        describe('Create', () => {
            let app
            beforeEach(async () => {
                [app] = await createTestB2BApp(creator)
            })
            test('Admin can create for any app', async () => {
                const [accessRightSet] = await createTestB2BAppAccessRightSet(admin, app)
                expect(accessRightSet).toHaveProperty('id')
            })
            test('Support can create for any app', async () => {
                const [accessRightSet] = await createTestB2BAppAccessRightSet(support, app)
                expect(accessRightSet).toHaveProperty('id')
            })
            describe('User', () => {
                test('Can create for app he owns', async () => {
                    const [accessRightSet] = await createTestB2BAppAccessRightSet(creator, app)
                    expect(accessRightSet).toHaveProperty('id')
                })
                test('Cannot create for app he does not own', async () => {
                    await expectToThrowAccessDeniedErrorToObj(async () => {
                        await createTestB2BAppAccessRightSet(anotherUser, app)
                    })
                })
            })
            test('Anonymous cannot create for any app', async () => {
                await expectToThrowAuthenticationErrorToObj(async () => {
                    await createTestB2BAppAccessRightSet(anonymous, app)
                })
            })
        })
        describe('Update', () => {
            let app
            let accessRightSet
            beforeEach(async () => {
                [app] = await createTestB2BApp(creator);
                [accessRightSet] = await createTestB2BAppAccessRightSet(creator, app)
            })
            test('Admin can update any accessRightSet', async () => {
                const [updatedAccessRightSet] = await updateTestB2BAppAccessRightSet(admin, accessRightSet.id, {
                    status: B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS,
                })
                expect(updatedAccessRightSet).toHaveProperty('id')
                expect(updatedAccessRightSet).toHaveProperty('status', B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS)
            })
            test('Support can update any accessRightSet', async () => {
                const [updatedAccessRightSet] = await updateTestB2BAppAccessRightSet(support, accessRightSet.id, {
                    status: B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS,
                })
                expect(updatedAccessRightSet).toHaveProperty('id')
                expect(updatedAccessRightSet).toHaveProperty('status', B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS)
            })
            test('User cannot update any accessRightSet', async () => {
                await expectToThrowAccessDeniedErrorToObj(async () => {
                    await updateTestB2BAppAccessRightSet(creator, accessRightSet.id)
                })
            })
            test('Anonymous cannot update any accessRightSet', async () => {
                await expectToThrowAuthenticationErrorToObj(async () => {
                    await updateTestB2BAppAccessRightSet(anonymous, accessRightSet.id)
                })
            })
        })
        describe('Read', () => {
            let app
            let accessRightSet
            beforeAll(async () => {
                [app] = await createTestB2BApp(creator);
                [accessRightSet] = await createTestB2BAppAccessRightSet(creator, app)
            })
            test('Admin can read any accessRightSet', async () => {
                const readRightSets = await B2BAppAccessRightSet.getAll(admin, {
                    id_in: [accessRightSet.id],
                })
                expect(readRightSets).toHaveLength(1)
            })
            test('Support can read any accessRightSet', async () => {
                const readRightSets = await B2BAppAccessRightSet.getAll(support, {
                    id_in: [accessRightSet.id],
                })
                expect(readRightSets).toHaveLength(1)
            })
            test('User can only read right sets linked to owned app', async () => {
                const creatorReadRightSets = await B2BAppAccessRightSet.getAll(creator, {
                    id_in: [accessRightSet.id],
                })
                expect(creatorReadRightSets).toHaveLength(1)

                const otherReadRightSets = await B2BAppAccessRightSet.getAll(anotherUser, {})
                expect(otherReadRightSets).toHaveLength(0)
            })
            test('Anonymous cannot read any accessRightSet', async () => {
                await expectToThrowAuthenticationErrorToObjects(async () => {
                    await B2BAppAccessRightSet.getAll(anonymous, {})
                })
            })
        })
        test('Hard-deleted is banned', async () => {
            const [app] = await createTestB2BApp(creator)
            const [rightSet] = await createTestB2BAppAccessRightSet(creator, app)
            await expectToThrowAccessDeniedErrorToObj(async () => {
                await B2BAppAccessRightSet.delete(admin, rightSet.id)
            })
            await expectToThrowAccessDeniedErrorToObj(async () => {
                await B2BAppAccessRightSet.delete(support, rightSet.id)
            })
            await expectToThrowAccessDeniedErrorToObj(async () => {
                await B2BAppAccessRightSet.delete(creator, rightSet.id)
            })
        })
    })
    describe('Logic tests', () => {
        describe('status field', () => {
            test(`Must be auto-updated to ${B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS} for non-prod environment`, async () => {
                const [app] = await createTestB2BApp(creator)
                const [rightSet] = await createTestB2BAppAccessRightSet(creator, app, { environment: DEV_ENVIRONMENT })
                expect(rightSet).toHaveProperty('status', B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS)
            })
            test(`Must not be auto-updated to ${B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS} for prod environment`, async () => {
                const [app] = await createTestB2BApp(creator)
                const [rightSet] = await createTestB2BAppAccessRightSet(creator, app, { environment: PROD_ENVIRONMENT })
                expect(rightSet).toHaveProperty('status', B2B_APP_ACCESS_RIGHT_SET_PENDING_STATUS)
            })
            describe(`Cannot be set to ${B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS} by app owner`, () => {
                test.each([DEV_ENVIRONMENT, PROD_ENVIRONMENT])('%p environment', async (environment) => {
                    const [app] = await createTestB2BApp(creator)
                    await expectToThrowAccessDeniedErrorToObj(async () => {
                        await createTestB2BAppAccessRightSet(creator, app, { environment, status: B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS })
                    })
                })
            })
        })
        describe('diff field', () => {
            describe('Must be resolved correctly', () => {
                test(`Must be empty for ${B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS} status`, async () => {
                    const [app] = await createTestB2BApp(creator)
                    const [rightSet] = await createTestB2BAppAccessRightSet(admin, app, {
                        environment: DEV_ENVIRONMENT,
                        canReadContacts: true,
                    })
                    const readRightSet = await B2BAppAccessRightSet.getOne(admin, { id: rightSet.id })
                    expect(readRightSet).toHaveProperty('status', B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS)
                    expect(readRightSet.diff).toEqual({ added: [], removed: [] })
                })
                test('Must treat non-existing approved set as all-false', async () => {
                    const [app] = await createTestB2BApp(creator)
                    const [rightSet] = await createTestB2BAppAccessRightSet(admin, app, {
                        environment: PROD_ENVIRONMENT,
                        canReadContacts: true,
                        canManageContacts: true,
                    })
                    const readRightSet = await B2BAppAccessRightSet.getOne(admin, { id: rightSet.id })
                    expect(readRightSet).toHaveProperty('status', B2B_APP_ACCESS_RIGHT_SET_PENDING_STATUS)
                    expect(readRightSet.diff.added).toEqual(expect.arrayContaining(['canReadContacts', 'canManageContacts']))
                    expect(readRightSet.diff.added).toHaveLength(2)
                    expect(readRightSet.diff.removed).toEqual([])
                })
                test('Must resolve diff correctly from currently approved right set', async () => {
                    const [app] = await createTestB2BApp(creator)
                    await createTestB2BAppAccessRightSet(admin, app, {
                        environment: PROD_ENVIRONMENT,
                        status: B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS,
                        canReadContacts: true,
                        canManageContacts: true,
                    })
                    const [pendingRightSet] = await createTestB2BAppAccessRightSet(admin, app, {
                        environment: PROD_ENVIRONMENT,
                        canReadContacts: true,
                        canReadProperties: true,
                    })
                    const readRightSet = await B2BAppAccessRightSet.getOne(admin, { id: pendingRightSet.id })
                    expect(readRightSet.diff.added).toEqual(['canReadProperties'])
                    expect(readRightSet.diff.removed).toEqual(['canManageContacts'])
                })
            })
        })
        describe('Creating new right set must auto-replace existing one with same status',  () => {
            test.each([B2B_APP_ACCESS_RIGHT_SET_PENDING_STATUS, B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS])('Must auto-replace existing right set with status %s', async (status) => {
                const environment = status === B2B_APP_ACCESS_RIGHT_SET_APPROVED_STATUS ? DEV_ENVIRONMENT : PROD_ENVIRONMENT
                const [app] = await createTestB2BApp(creator)
                const [rightSet] = await createTestB2BAppAccessRightSet(creator, app, { environment })
                expect(rightSet).toHaveProperty('status', status)
                expect(rightSet).toHaveProperty('environment', environment)

                const [newRightSet] = await createTestB2BAppAccessRightSet(creator, app, { environment })
                expect(newRightSet).toHaveProperty('status', status)
                expect(newRightSet).toHaveProperty('environment', environment)

                const previousRightSet = await B2BAppAccessRightSet.getOne(creator, { id: rightSet.id })
                expect(previousRightSet).not.toBeDefined()
            })
        })
    })
})
